<template><div class="min-h-screen flex flex-col bg-[#FFF9F9] text-rose-950 font-sans selection:bg-rose-200 overflow-hidden relative text-center px-4"><div class="fixed inset-0 overflow-hidden pointer-events-none"><div class="absolute -top-20 -left-20 w-80 h-80 bg-rose-200/40 rounded-full blur-[100px] animate-pulse"></div><div class="absolute top-1/3 -right-20 w-96 h-96 bg-orange-100/30 rounded-full blur-[120px]"></div></div><header class="relative z-10 pt-10 pb-6"><div class="inline-flex items-center gap-2 px-3 py-1 bg-white/40 backdrop-blur-md rounded-full border border-white/50 mb-4 shadow-sm"><span class="flex h-2 w-2 rounded-full bg-rose-400 animate-ping"></span><span class="text-[10px] font-black tracking-widest text-rose-500 uppercase">AI Beauty Intel</span></div><h1 class="text-3xl font-black bg-gradient-to-b from-rose-500 to-rose-700 bg-clip-text text-transparent">猫咪颜究所</h1><p class="text-xs text-rose-400 mt-2 font-medium">专业测评 · 品相鉴别 · 避坑指南 ✨</p></header><main class="relative z-10 flex-1 max-w-md mx-auto w-full"><section v-if="step==='home'" class="space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-1000"><div class="bg-white/40 backdrop-blur-2xl rounded-[2.5rem] p-8 shadow-2xl border border-white/60 text-center"><label class="block text-[10px] font-black text-rose-300 mb-6 uppercase tracking-widest">Step 1: 选择品种 Breed</label><div class="grid grid-cols-2 gap-3"><button v-for="b in breeds" :key="b" @click="breed=b" :class="breed===b?'bg-rose-500 text-white shadow-lg shadow-rose-200 scale-105':'bg-white/60 text-rose-400'" class="flex items-center justify-center gap-2 py-4 px-2 rounded-2xl font-bold text-xs transition-all border border-white/40"><span>{{ b==='自动识别'?'🔍':b==='布偶猫'?'👸':b==='英国短毛猫'?'🐱':b==='美国短毛猫'?'🐾':'✨' }}</span>{{ b }}</button></div></div><div class="space-y-4"><button @click="openCamera" class="w-full py-6 rounded-3xl bg-rose-500 text-white font-black shadow-lg shadow-rose-200 active:scale-95 transition-all flex items-center justify-center gap-3 relative overflow-hidden group"><div class="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000"></div><span class="text-2xl">📸</span><span class="tracking-widest font-black uppercase">开启评测</span></button><input ref="fileInput" type="file" accept="image/*" class="hidden" @change="onFileSelected"/><button @click="openAlbum" class="w-full py-6 rounded-3xl bg-white/60 backdrop-blur-md border border-white text-rose-400 font-bold active:scale-95 transition-all flex items-center justify-center gap-3 shadow-sm"><span class="text-xl">🎞️</span><span class="tracking-widest font-black uppercase">从手机相册选</span></button></div></section><section v-if="step==='loading'" class="flex flex-col items-center justify-center py-32"><div class="relative w-32 h-32"><div class="absolute inset-0 rounded-full border-[10px] border-white shadow-lg"></div><div class="absolute inset-0 rounded-full border-[10px] border-t-rose-400 animate-spin"></div><div class="absolute inset-0 flex items-center justify-center text-3xl animate-pulse">💖</div></div><div class="mt-12 text-center"><h3 class="text-xl font-black text-rose-500 mb-2">{{ loadingText }}</h3><p class="text-[10px] text-rose-300 font-bold uppercase tracking-widest leading-relaxed">基于专业标准生成报告</p></div></section><section v-if="step==='result'&&result" class="space-y-8 animate-in fade-in slide-in-from-bottom-12 duration-1000"><div class="bg-white/60 backdrop-blur-3xl rounded-[3.5rem] shadow-2xl border border-white overflow-hidden pb-10 px-6 text-center"><div class="p-10 text-center"><div class="inline-block px-4 py-1.5 rounded-full bg-rose-500 text-white text-[10px] font-black uppercase mb-6 shadow-lg shadow-rose-200 tracking-widest">Expert Report</div><h2 class="text-4xl font-black text-rose-600 mb-8 tracking-tighter">{{ result.identified_breed }}</h2><div class="relative inline-flex mb-10 group"><div class="absolute inset-0 rounded-full bg-rose-400/20 blur-2xl group-hover:blur-3xl transition-all duration-1000"></div><svg class="w-40 h-40 transform -rotate-90 relative"><circle cx="80" cy="80" r="72" stroke="currentColor" stroke-width="12" fill="transparent" class="text-white/80"/><circle cx="80" cy="80" r="72" stroke="currentColor" stroke-width="12" fill="transparent" class="text-rose-400 transition-all duration-1500 ease-out" :style="{strokeDasharray:452.4,strokeDashoffset:452.4*(1-result.total_score/100)}"/></svg><div class="absolute inset-0 flex flex-col items-center justify-center"><span class="text-5xl font-black text-rose-500 tracking-tighter">{{ result.total_score }}</span><span class="text-[11px] font-black text-rose-300 uppercase">Points</span></div></div><div class="flex justify-center"><div :class="gradeClass(result.grade)" class="px-8 py-3 rounded-full text-[10px] font-black shadow-sm tracking-[0.2em] uppercase">{{ result.grade }}</div></div></div><div class="space-y-6"><div v-for="(content, key) in result.detailed_analysis" :key="key" class="bg-white/40 p-6 rounded-[2.5rem] border border-white/60 shadow-sm text-center"><span class="text-[10px] font-black text-rose-300 uppercase block mb-2">{{ key==='head'?'头部亮点':key==='body'?'身形结构':'被毛氛围' }}</span><p class="text-sm text-rose-950/70 font-bold">{{ content }}</p></div><div class="grid grid-cols-2 gap-4"><div class="bg-emerald-50/40 p-5 rounded-[2rem] border border-emerald-100/50 text-[11px] text-emerald-700 font-bold text-center">优点 Pros<ul><li v-for="pro in result.pros" :key="pro" class="mt-1">{{ pro }}</li></ul></div><div class="bg-rose-50/40 p-5 rounded-[2rem] border border-rose-100/50 text-[11px] text-rose-700 font-bold text-center">不足 Cons<ul><li v-for="con in result.cons" :key="con" class="mt-1">{{ con }}</li></ul></div></div><div class="bg-rose-500 p-8 rounded-[2.5rem] text-white shadow-xl flex items-center justify-between transition-all"><div class="text-left"><span class="text-[10px] font-black text-rose-100/80 uppercase block mb-1">Estimated Value</span><p class="text-2xl font-black tracking-tight">{{ result.price_estimate }}</p></div><div class="text-4xl">🏷️</div></div><div class="bg-rose-50/60 p-6 rounded-[2rem] border border-white text-center"><span class="text-[10px] font-black text-rose-300 uppercase block mb-3">避坑建议 Advice</span><p class="text-sm text-rose-800 font-bold italic leading-relaxed">"{{ result.expert_advice }}"</p></div></div></div><button @click="reset" class="w-full py-6 rounded-4xl bg-rose-100 text-rose-500 font-black mb-8 tracking-widest uppercase text-xs active:scale-95 transition-all">再测一只 🐱</button></section></main><footer class="relative z-10 py-10 opacity-30 text-[10px] font-black text-rose-500 uppercase tracking-[0.4em]">AI Beauty Lab · Pro Edition</footer></div></template><script setup>import {ref,computed} from 'vue';import {compressImage} from './utils/compress.js';const breeds=['自动识别','布偶猫','英国短毛猫','美国短毛猫','其他'],breed=ref('自动识别'),step=ref('home'),result=ref(null),uploading=ref(false),fileInput=ref(null),loadingTexts=['正在扫描特征...','正在鉴别品相...','正在预估市场参考价...','正在生成专业建议...','报告即将呈现...'],loadingTextIndex=ref(0);let loadingInterval=null;const loadingText=computed(()=>loadingTexts[loadingTextIndex.value]);function startLoadingAnimation(){loadingTextIndex.value=0;loadingInterval=setInterval(()=>{if(loadingTextIndex.value<loadingTexts.length-1)loadingTextIndex.value++},2500)}function stopLoadingAnimation(){if(loadingInterval){clearInterval(loadingInterval);loadingInterval=null}}function gradeClass(g){if(g==='赛级')return 'bg-amber-100 text-amber-600 border-amber-200';if(g==='繁育级')return 'bg-rose-100 text-rose-600 border-rose-200';return 'bg-white/80 text-rose-400 border-rose-100'}function getApiBase(){return import.meta.env.DEV?'':(import.meta.env.VITE_API_BASE||'')}async function uploadAndEvaluate(blob){step.value='loading';startLoadingAnimation();uploading.value=true;result.value=null;try{const form=new FormData();form.append('file',blob,'cat.jpg');form.append('breed',breed.value);const res=await fetch(`${getApiBase()}/api/evaluate`,{method:'POST',body:form,signal:AbortSignal.timeout(120000)});if(!res.ok){const err=await res.json().catch(()=>({}));throw new Error(err.detail||res.statusText||'请求失败')}result.value=await res.json();step.value='result'}catch(e){alert('评估失败：'+(e.message||String(e)));step.value='home'}finally{uploading.value=false;stopLoadingAnimation()}}function openCamera(){if(!fileInput.value)return;fileInput.value.setAttribute('capture','environment');fileInput.value.click()}function openAlbum(){if(!fileInput.value)return;fileInput.value.removeAttribute('capture');fileInput.value.click()}async function onFileSelected(ev){const file=ev.target.files?.[0];if(!file)return;ev.target.value='';try{const blob=await compressImage(file,1200,0.82);await uploadAndEvaluate(blob)}catch(e){alert('处理失败：'+String(e))}}function reset(){step.value='home';result.value=null}</script><style>@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+SC:wght@400;700;900&display=swap');body{-webkit-tap-highlight-color:transparent;background:#FFF9F9;font-family:'Noto Sans SC',sans-serif}::-webkit-scrollbar{display:none}.rounded-4xl{border-radius:2rem}</style>
